{
  "schema_version": 1,
  "request_id": "rf-suggest-ghost-chain-feed-valve-flash-alternate-candidate-tab-after-other-skip-001",
  "project": "radishflow",
  "task": "suggest_ghost_completion",
  "answers": [
    {
      "summary": "当前已选中 Flash Drum 512，其 vapor_outlet 端口未连接。检测到两个下游候选流桩，其中主候选（VG-512）具有高置信度且为 Tab 默认，但最近一次跳过操作针对的是另一个候选（legacy），因此主候选仍可正常建议。",
      "issues": [],
      "proposed_actions": [
        {
          "action": "ghost_completion",
          "ghost_completion": {
            "title": "连接 Flash Drum 512 的 vapor_outlet 至主下游流桩 VG-512",
            "target": {
              "unit_id": "flash-40",
              "port_key": "vapor_outlet"
            },
            "rationale": "主候选（cand-flash-40-vapor-outlet-main）具有高对齐分数（0.96）、高拓扑分数（0.94）且与上游命名模式一致（VG-512），是当前最合理的连接建议。",
            "patch": {
              "operations": [
                {
                  "op": "add",
                  "path": "/streams/-",
                  "value": {
                    "id": "VG-512",
                    "name": "VG-512",
                    "source_unit_id": "flash-40",
                    "source_port": "vapor_outlet",
                    "target_unit_id": null,
                    "target_port": null
                  }
                }
              ]
            },
            "preview": {
              "accept_key": "Tab",
              "description": "按 Tab 键接受建议，将创建名为 VG-512 的流，连接 Flash Drum 512 的 vapor_outlet 至主下游流桩。",
              "manual_only": false
            },
            "apply": {
              "command_kind": "accept_ghost_completion",
              "command_args": {
                "candidate_ref": "cand-flash-40-vapor-outlet-main"
              }
            },
            "risk_level": "low",
            "requires_confirmation": false
          }
        }
      ]
    }
  ]
}
